```javascript
d3_force_directed_graph = (
  data,
  link_force = 0.5,
  repel_force = -250,
  center_force = 0.1,
  zoom_factor = 1,
  width = 1500,
  height = 1200
) => {
  const color = d3.scaleOrdinal(d3.schemeCategory10);
  const links = data.links.map(d => ({ ...d }));
  const nodes = data.nodes.map(d => ({ ...d, frozen: false }));
  const simulation = d3.forceSimulation(nodes)
    .force("link", d3.forceLink(links).id(d => d.id).strength(link_force))
    .force("charge", d3.forceManyBody().strength(repel_force))
    .force("center", d3.forceCenter(width / 2, height / 2).strength(center_force))
    .on("tick", ticked);

  const svg = d3.create("svg")
    .attr("width", width)
    .attr("height", height)
    .attr("viewBox", [0, 0, width, height])
    .attr("style", "max-width: 100%; height: auto;")
    .call(d3.zoom().scaleExtent([0.1, 10]).on("zoom", (event) => {
      g.attr("transform", event.transform);
    }));

  const g = svg.append("g")
    .attr("transform", `scale(${zoom_factor})`);

  const link = g.append("g")
    .attr("stroke", "#999")
    .attr("stroke-opacity", 0.8)
    .selectAll()
    .data(links)
    .join("line")
    .attr("stroke-width", d => Math.sqrt(d.value));

  // Set node size based on the group
  const node = g.append("g")
    .attr("stroke-width", 1.5)
    .selectAll()
    .data(nodes)
    .join("circle")
    .attr("r", d => d.group === "category" ? 15 : d.group === "topic" ? 5 : 10)
    .attr("fill", d => color(d.group))
    .attr("opacity", 0.7)  // Set default transparency to 0.7
    .on("mouseover", mouseovered)
    .on("mouseout", mouseouted)
    .on("click", clicked);

  const label = g.append("g")
    .selectAll("text")
    .data(nodes)
    .join("text")
    .text(d => d.id)
    .attr("x", 6)
    .attr("y", 3);

  node.call(d3.drag()
    .on("start", dragstarted)
    .on("drag", dragged)
    .on("end", dragended));

  function ticked() {
    link
      .attr("x1", d => d.source.x)
      .attr("y1", d => d.source.y)
      .attr("x2", d => d.target.x)
      .attr("y2", d => d.target.y);

    node
      .attr("cx", d => {
        if (d.x < 0) {
          d.vx = Math.abs(d.vx);
          d.x = 0;
        } else if (d.x > width) {
          d.vx = -Math.abs(d.vx);
          d.x = width;
        }
        return d.x;
      })
      .attr("cy", d => {
        if (d.y < 0) {
          d.vy = Math.abs(d.vy);
          d.y = 0;
        } else if (d.y > height) {
          d.vy = -Math.abs(d.vy);
          d.y = height;
        }
        return d.y;
      });

    label
      .attr("x", d => d.x + 6)
      .attr("y", d => d.y + 3);
  }

  function dragstarted(event) {
    if (!event.active) simulation.alphaTarget(0.3).restart();
    event.subject.fx = event.subject.x;
    event.subject.fy = event.subject.y;
  }

  function dragged(event) {
    event.subject.fx = event.x;
    event.subject.fy = event.y;
  }

  function dragended(event) {
    if (!event.active) simulation.alphaTarget(0);
    event.subject.frozen = true;
    updateStyles();
  }

  function updateStyles() {
    const frozenNodesIds = new Set(nodes.filter(n => n.frozen).map(n => n.id));
    const highlighted = new Set();
    link.each(l => {
      if (frozenNodesIds.has(l.source.id) || frozenNodesIds.has(l.target.id)) {
        highlighted.add(l.source.id).add(l.target.id);
      }
    });
    const hasFrozenNodes = frozenNodesIds.size > 0;
    node.style("opacity", n => {
      return n.frozen || highlighted.has(n.id) ? 1 : (hasFrozenNodes ? 0.5 : 0.7);
    })
    .attr("stroke", n => (n.frozen ? "blue" : null));
    label.style("opacity", n => {
      return n.frozen || highlighted.has(n.id) ? 1 : (hasFrozenNodes ? 0.5 : 0.7);
    });
    link.style("stroke-opacity", l => {
      return (frozenNodesIds.has(l.source.id) || frozenNodesIds.has(l.target.id)) ? 1.0 : (hasFrozenNodes ? 0.3 : 0.8);
    });
  }

  function mouseovered(event, d) {
    const connectedNodes = new Set([d.id]);
    link.style("stroke-opacity", l => {
      if (l.source.id === d.id || l.target.id === d.id) {
        connectedNodes.add(l.source.id).add(l.target.id);
        return 1.0;
      }
      return 0.3;
    });
    node.style("opacity", n => {
      return connectedNodes.has(n.id) || n.frozen ? 1 : 0.5;
    })
    .attr("stroke", n => (connectedNodes.has(n.id) || n.frozen ? "blue" : null));
    label.style("opacity", n => {
      return connectedNodes.has(n.id) || n.frozen ? 1 : 0.5;
    });
  }

  function mouseouted() {
    updateStyles();
  }

  function clicked(event, d) {
    d.frozen = !d.frozen;
    if (!d.frozen) {
      d.fx = null;
      d.fy = null;
      simulation.alpha(1).restart();
    }
    updateStyles();
  }

  return svg.node();
}
